'use client';

import Image from 'next/image';
import Link from 'next/link';
import { getProductById } from '@/data/products';
import { useCart } from '@/contexts/CartContext';
import { CATEGORY_LABELS } from '@/types/shop';

export default function CartContent() {
  const { cart, removeItem, updateQuantity, clearCart } = useCart();
  const cartItems = cart.items
    .map((item) => {
      const product = getProductById(item.productId);
      return product ? { item, product } : null;
    })
    .filter((entry): entry is NonNullable<typeof entry> => Boolean(entry));

  const shippingCost = cart.total >= 50 ? 0 : 6.95;
  const totalWithShipping = cart.total + shippingCost;
  const missingProducts = cart.items.length - cartItems.length;

  if (cartItems.length === 0) {
    return (
      <div className="min-h-screen bg-slate-50">
        <div className="container mx-auto px-4 py-16">
          <div className="mx-auto max-w-md text-center">
            <div className="mb-4 text-6xl">🛒</div>
            <h1 className="mb-4 text-3xl font-bold text-slate-900">Uw winkelwagen is leeg</h1>
            <p className="mb-8 text-slate-600">
              Voeg producten toe om te beginnen met winkelen
            </p>
            <Link
              href="/shop"
              className="inline-block rounded-2xl bg-slate-900 px-8 py-3 font-medium text-white transition-colors hover:bg-slate-800"
            >
              Naar de shop
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      <div className="container mx-auto px-4 py-8">
        <div className="mb-8 flex flex-wrap items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold text-slate-900">Winkelwagen</h1>
            <p className="mt-2 text-slate-600">
              {cartItems.length} productregel{cartItems.length === 1 ? '' : 's'} in uw winkelwagen
            </p>
          </div>
          <Link
            href="/shop"
            className="rounded-full border border-slate-300 px-4 py-2 text-sm font-medium text-slate-700 transition hover:border-slate-400 hover:bg-white"
          >
            Verder winkelen
          </Link>
        </div>

        {missingProducts > 0 && (
          <div className="mb-6 rounded-2xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800">
            {missingProducts} product{missingProducts > 1 ? 'en zijn' : ' is'} niet meer beschikbaar en worden niet getoond in het overzicht.
          </div>
        )}

        <div className="grid gap-8 lg:grid-cols-3">
          <div className="space-y-4 lg:col-span-2">
            {cartItems.map(({ item, product }) => (
              <div
                key={item.productId}
                className="flex gap-5 rounded-[2rem] border border-slate-200 bg-white p-5 shadow-sm"
              >
                <div className="relative h-24 w-24 flex-shrink-0 overflow-hidden rounded-2xl bg-gradient-to-br from-slate-100 via-white to-sky-50">
                  <Image
                    src={product.images[0]}
                    alt={product.name}
                    fill
                    sizes="96px"
                    className="object-contain p-3"
                  />
                </div>

                <div className="flex-1">
                  <h3 className="mb-1 text-lg font-bold text-slate-900">{product.name}</h3>
                  <p className="mb-3 text-sm text-slate-500">
                    {CATEGORY_LABELS[product.category]}
                    {product.brand ? ` • ${product.brand}` : ''}
                    {product.sku ? ` • SKU: ${product.sku}` : ''}
                  </p>
                  <div className="flex items-center gap-4">
                    <div className="flex items-center rounded-2xl border border-slate-300">
                      <button
                        onClick={() => updateQuantity(item.productId, item.quantity - 1)}
                        className="px-3 py-1 transition-colors hover:bg-slate-100"
                      >
                        -
                      </button>
                      <span className="border-x border-slate-300 px-4 py-1">{item.quantity}</span>
                      <button
                        onClick={() => updateQuantity(item.productId, item.quantity + 1)}
                        className="px-3 py-1 transition-colors hover:bg-slate-100"
                      >
                        +
                      </button>
                    </div>
                    <button
                      onClick={() => removeItem(item.productId)}
                      className="text-sm font-medium text-rose-600 hover:text-rose-700"
                    >
                      Verwijderen
                    </button>
                  </div>
                </div>

                <div className="text-right">
                  <p className="text-2xl font-bold text-slate-900">
                    €{(item.price * item.quantity).toFixed(2)}
                  </p>
                  <p className="text-sm text-slate-500">€{item.price.toFixed(2)} per stuk</p>
                </div>
              </div>
            ))}

            <button
              onClick={clearCart}
              className="text-sm font-medium text-rose-600 hover:text-rose-700"
            >
              Winkelwagen legen
            </button>
          </div>

          <div className="lg:col-span-1">
            <div className="sticky top-4 rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
              <h2 className="mb-4 text-xl font-bold text-slate-900">Overzicht</h2>

              <div className="mb-6 space-y-3">
                <div className="flex justify-between text-slate-600">
                  <span>Subtotaal</span>
                  <span>€{cart.total.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-slate-600">
                  <span>Verzendkosten</span>
                  <span>
                    {shippingCost === 0 ? (
                      <span className="font-medium text-emerald-600">Gratis</span>
                    ) : (
                      `€${shippingCost.toFixed(2)}`
                    )}
                  </span>
                </div>
                {cart.total < 50 && (
                  <div className="rounded-2xl border border-sky-200 bg-sky-50 p-3">
                    <p className="text-sm text-sky-800">
                      Nog €{(50 - cart.total).toFixed(2)} tot gratis verzending! 🚚
                    </p>
                  </div>
                )}
                <div className="flex justify-between border-t border-slate-200 pt-3 text-lg font-bold">
                  <span>Totaal</span>
                  <span className="text-slate-900">€{totalWithShipping.toFixed(2)}</span>
                </div>
              </div>

              <Link
                href="/contact"
                className="mb-3 block w-full rounded-2xl bg-slate-900 py-3 text-center font-bold text-white transition-colors hover:bg-slate-800"
              >
                Offerte of bestelling aanvragen
              </Link>

              <p className="mb-3 text-center text-xs text-slate-500">
                Gebruik het contactformulier om levering, plaatsing of extra advies af te stemmen.
              </p>

              <Link href="/shop" className="block w-full text-center text-sky-700 hover:underline">
                Verder winkelen
              </Link>

              <div className="mt-6 space-y-2 border-t border-slate-200 pt-6 text-sm text-slate-600">
                <p>✓ Veilig betalen</p>
                <p>✓ 14 dagen retourrecht</p>
                <p>✓ Gratis verzending vanaf €50</p>
                <p>✓ Besteld voor 15:00, morgen in huis</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
